#include&lt;bits/stdc++.h&gt;#define maxn 200010using namespace std;typedef long long ll;template&lt;typename T&gt; inline void read(T &amp;x){    x=0;char c=getchar();bool flag=false;    while(!isdigit(c)){if(c=='-')flag=true;c=getchar();}    while(isdigit(c)){x=(x&lt;&lt;1)+(x&lt;&lt;3)+(c^48);c=getchar();}    if(flag)x=-x;}int n,m;ll ans;int l[maxn],r[maxn],id[maxn];set&lt;pair&lt;int,int&gt; &gt; s;map&lt;pair&lt;int,int&gt;,bool&gt; mp;bool vis[maxn],V[maxn],vis2[maxn];ll calc(int R){    if(V[R]) return 0;    V[R]=true;    ll val=0;    for(int i=1;i&lt;=m;++i) vis[i]=false;    for(int i=1;i&lt;=n;++i) vis2[i]=false;    int pos=0,id=0,mx=0;    for(int i=1;i&lt;=m;++i)    {        if(l[i]&gt;pos&amp;&amp;r[i]==R)        {            pos=l[i];            id=i;        }    }    vis[id]=true;    vis2[pos]=true;    val++;    priority_queue&lt;pair&lt;int,int&gt; &gt; q;    for(int i=1;i&lt;=m;++i)    {        if(vis[i]) continue;        if(r[i]&lt;=R)        {            q.push(make_pair(l[i],r[i]));        }    }    while(!q.empty())    {        int l=q.top().first,r=q.top().second;        q.pop();        if(r&gt;=pos-1&amp;&amp;l&lt;pos)        {            pos=l;            if(!vis2[pos])            {                vis2[pos]=true;                val++;            }        }    }    return val;}int main(){    read(n),read(m);    for(int i=1;i&lt;=m;++i) read(l[i]),read(r[i]);    for(int i=1;i&lt;=m;++i) ans+=calc(r[i]);    cout&lt;&lt;ans;    return 0;}
